document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("projectMainImg"),t=document.querySelector(".gallerySlider .owl-stage"),l=document.querySelectorAll(".gallerySlider .img img"),r=document.querySelector(".gallerySlider .owl-prev"),n=document.querySelector(".gallerySlider .owl-next");let c=0;l.forEach((t,l)=>{t.addEventListener("click",()=>{e.innerHTML=` <img src="${t.src}" alt="Main Image">`,document.querySelectorAll(".gallerySlider .img").forEach(e=>e.classList.remove("active")),t.parentElement.classList.add("active"),c=l})});const a=document.querySelector(".gallerySlider .owl-item").offsetWidth+10;function i(){const t=l[c];e.innerHTML=`<img src="${t.src}" alt="Main Image">`,document.querySelectorAll(".gallerySlider .img").forEach(e=>e.classList.remove("active")),t.parentElement.classList.add("active")}r.addEventListener("click",()=>{c--,c<0&&(c=l.length-1),t.style.transform=`translateX(${a*c/3}px)`,i()}),n.addEventListener("click",()=>{c++,c>=l.length&&(c=0),t.style.transform=`translateX(${a*c/3}px)`,i()})});